import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { PRODUCTS } from './constants';
import { 
  ArrowLeft, Plus, Minus, ShieldCheck, Truck, RotateCcw, 
  Check, ShoppingBag, ChevronLeft, ChevronRight 
} from 'lucide-react';
import { useCart } from './CartContext';

const ProductDetail: React.FC = () => {
  const { id } = useParams();
  const product = PRODUCTS.find(p => p.id === id) || PRODUCTS[0];
  const { addToCart } = useCart();

  const [quantity, setQuantity] = useState(1);
  const [isAdding, setIsAdding] = useState(false);
  const [currentSlide, setCurrentSlide] = useState(0);

  // Determine back link based on product origin
  const isVaultItem = product.tag === 'VAULT';
  const backToPath = isVaultItem ? '/vault/shop' : '/collections';
  const backToLabel = 'Back to Collection';

  // Prepare all slides (Main image + Gallery)
  const allSlides = [product.image, ...(product.gallery || [])];

  const handleAddToCart = () => {
    setIsAdding(true);
    addToCart(product, quantity);
    setTimeout(() => setIsAdding(false), 2000);
  };

  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % allSlides.length);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + allSlides.length) % allSlides.length);
  };

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'ArrowLeft') prevSlide();
      if (e.key === 'ArrowRight') nextSlide();
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [allSlides.length]);

  return (
    <main className="bg-black min-h-screen pt-32 pb-24 selection:bg-[#D4AF37] selection:text-black">
      <div className="max-w-[1800px] mx-auto px-6 md:px-12">
        <Link 
          to={backToPath} 
          className="inline-flex items-center gap-3 text-[10px] tracking-[0.4em] font-bold text-white/40 hover:text-white transition-colors uppercase mb-12 group"
        >
          <ArrowLeft size={14} className="group-hover:-translate-x-1 transition-transform" /> {backToLabel}
        </Link>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-16 xl:gap-24">
          {/* Slider Section */}
          <div className="lg:col-span-7 xl:col-span-8 space-y-8">
            <div className="relative aspect-square bg-[#0d0d0d] border border-white/5 overflow-hidden group">
              {/* Image Container with Swipe Support */}
              <div className="w-full h-full relative overflow-hidden touch-pan-y">
                <AnimatePresence mode="wait" initial={false}>
                  <motion.div
                    key={currentSlide}
                    initial={{ opacity: 0, x: 20 }}
                    animate={{ opacity: 1, x: 0 }}
                    exit={{ opacity: 0, x: -20 }}
                    transition={{ duration: 0.5, ease: [0.33, 1, 0.68, 1] }}
                    className="w-full h-full"
                    drag="x"
                    dragConstraints={{ left: 0, right: 0 }}
                    dragElastic={0.2}
                    onDragEnd={(_, info) => {
                      if (info.offset.x < -50) nextSlide();
                      if (info.offset.x > 50) prevSlide();
                    }}
                  >
                    <img 
                      src={allSlides[currentSlide]} 
                      alt={`${product.name} view ${currentSlide + 1}`} 
                      className="w-full h-full object-cover pointer-events-none select-none"
                    />
                  </motion.div>
                </AnimatePresence>
              </div>

              {/* Desktop Arrows */}
              <button 
                onClick={prevSlide}
                className="absolute left-6 top-1/2 -translate-y-1/2 w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md border border-white/10 text-white opacity-0 group-hover:opacity-100 transition-opacity hidden md:flex hover:bg-[#D4AF37] hover:text-black hover:border-[#D4AF37]"
                aria-label="Previous slide"
              >
                <ChevronLeft size={24} />
              </button>
              <button 
                onClick={nextSlide}
                className="absolute right-6 top-1/2 -translate-y-1/2 w-12 h-12 flex items-center justify-center bg-black/40 backdrop-blur-md border border-white/10 text-white opacity-0 group-hover:opacity-100 transition-opacity hidden md:flex hover:bg-[#D4AF37] hover:text-black hover:border-[#D4AF37]"
                aria-label="Next slide"
              >
                <ChevronRight size={24} />
              </button>

              {/* Slide Counter / Indicators */}
              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex gap-3">
                {allSlides.map((_, idx) => (
                  <button
                    key={idx}
                    onClick={() => setCurrentSlide(idx)}
                    className={`h-1 transition-all duration-500 ${currentSlide === idx ? 'w-12 bg-[#D4AF37]' : 'w-4 bg-white/20'}`}
                  />
                ))}
              </div>
            </div>

            {/* Thumbnail Selection */}
            <div className="grid grid-cols-4 gap-4">
              {allSlides.map((slide, idx) => (
                <button
                  key={idx}
                  onClick={() => setCurrentSlide(idx)}
                  className={`aspect-square bg-[#0d0d0d] border transition-all duration-500 overflow-hidden ${currentSlide === idx ? 'border-[#D4AF37] opacity-100' : 'border-white/5 opacity-40 hover:opacity-100'}`}
                >
                  <img src={slide} alt={`Thumbnail ${idx + 1}`} className="w-full h-full object-cover" />
                </button>
              ))}
            </div>
          </div>

          {/* Info Section */}
          <div className="lg:col-span-5 xl:col-span-4">
            <motion.div 
              initial={{ opacity: 0, x: 20 }}
              animate={{ opacity: 1, x: 0 }}
              transition={{ duration: 0.8, delay: 0.2 }}
              className="sticky top-40"
            >
              <p className="text-[#D4AF37] text-[10px] tracking-[0.5em] font-black uppercase mb-4">{product.tag || 'NEW ARRIVAL'}</p>
              <h1 className="text-4xl md:text-6xl font-black tracking-tighter uppercase mb-6 leading-none">{product.name}</h1>
              <p className="text-2xl font-black text-white mb-8">{product.price}</p>

              <div className="w-full h-[1px] bg-white/10 mb-8"></div>

              <p className="text-white/60 text-base font-light leading-relaxed mb-12">
                {product.description} Engineered for the urban nomad, this piece balances extreme durability with a silhouette that commands presence. 
                Hand-finished details ensure each unit is unique to its owner.
              </p>

              {/* Action Area */}
              <div className="space-y-8">
                <div className="flex items-center gap-8">
                  <span className="text-[10px] tracking-[0.4em] font-bold text-white/40 uppercase">Quantity</span>
                  <div className="flex items-center border border-white/10 bg-white/5">
                    <button 
                      onClick={() => setQuantity(Math.max(1, quantity - 1))}
                      className="p-4 hover:bg-white/5 transition-colors text-white/40 hover:text-white"
                    >
                      <Minus size={14} />
                    </button>
                    <span className="w-12 text-center text-[11px] font-black">{quantity}</span>
                    <button 
                      onClick={() => setQuantity(quantity + 1)}
                      className="p-4 hover:bg-white/5 transition-colors text-white/40 hover:text-white"
                    >
                      <Plus size={14} />
                    </button>
                  </div>
                </div>

                <button 
                  onClick={handleAddToCart}
                  disabled={isAdding}
                  className={`w-full py-6 text-[11px] tracking-[0.5em] font-black uppercase transition-all duration-500 flex items-center justify-center gap-4 relative overflow-hidden group
                    ${isAdding ? 'bg-[#D4AF37] text-black' : 'bg-white text-black hover:bg-[#D4AF37]'}`}
                >
                  <AnimatePresence mode="wait">
                    {isAdding ? (
                      <motion.div 
                        key="success"
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="flex items-center gap-2"
                      >
                        <Check size={18} /> Added to Bag
                      </motion.div>
                    ) : (
                      <motion.div 
                        key="default"
                        initial={{ opacity: 0, y: 10 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -10 }}
                        className="flex items-center gap-2"
                      >
                        <ShoppingBag size={18} /> Pre-Order
                      </motion.div>
                    )}
                  </AnimatePresence>
                </button>
              </div>

              {/* Trust Markers */}
              <div className="mt-16 grid grid-cols-1 gap-6">
                <div className="flex items-center gap-6 p-6 border border-white/5 bg-white/[0.02]">
                  <ShieldCheck size={24} className="text-[#D4AF37]" strokeWidth={1.5} />
                  <div>
                    <h5 className="text-[10px] tracking-[0.2em] font-black uppercase text-white mb-1">Lifetime Warranty</h5>
                    <p className="text-[9px] text-white/40 uppercase">On all hardware and stitching.</p>
                  </div>
                </div>
                <div className="flex items-center gap-6 p-6 border border-white/5 bg-white/[0.02]">
                  <Truck size={24} className="text-[#D4AF37]" strokeWidth={1.5} />
                  <div>
                    <h5 className="text-[10px] tracking-[0.2em] font-black uppercase text-white mb-1">Priority Logistics</h5>
                    <p className="text-[9px] text-white/40 uppercase">Complimentary express shipping global.</p>
                  </div>
                </div>
                <div className="flex items-center gap-6 p-6 border border-white/5 bg-white/[0.02]">
                  <RotateCcw size={24} className="text-[#D4AF37]" strokeWidth={1.5} />
                  <div>
                    <h5 className="text-[10px] tracking-[0.2em] font-black uppercase text-white mb-1">Seamless Exchanges</h5>
                    <p className="text-[9px] text-white/40 uppercase">30-day white glove return service.</p>
                  </div>
                </div>
              </div>
            </motion.div>
          </div>
        </div>
      </div>
    </main>
  );
};

export default ProductDetail;

