      <div className="absolute bottom-0 left-0 w-[50vw] h-[50vw] bg-[#D4AF37]/3 blur-[120px] rounded-full translate-y-1/2 -translate-x-1/2 pointer-events-none" />

      <div className="max-w-[1800px] mx-auto px-6 md:px-12 relative z-10">
        <Link to="/vault" className="inline-flex items-center gap-4 text-[10px] tracking-[0.5em] font-black uppercase text-white/40 hover:text-[#D4AF37] mb-20 transition-colors group">
          <ArrowLeft size={16} className="group-hover:-translate-x-2 transition-transform" /> Exit Private Shop
        </Link>

        <header className="mb-32">
          <motion.div
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.8 }}
          >
            <div className="flex items-center gap-6 mb-8">
              <div className="bg-[#D4AF37] p-3">
                <ShieldAlert size={20} className="text-black" />
              </div>
              <div className="space-y-1">
                <p className="text-[#D4AF37] text-[10px] tracking-[0.8em] font-black uppercase">Level 04 Clearance Required</p>
                <div className="flex items-center gap-2 text-white/40 text-[9px] font-bold uppercase tracking-widest">
                  <BadgeCheck size={12} className="text-[#D4AF37]" /> Verified Operative: GUEST_932
                </div>
              </div>
            </div>
            <h1 className="text-6xl md:text-9xl font-black tracking-[-0.05em] uppercase mb-12 italic leading-none">
              Vault<br />Shop.
            </h1>
            <p className="text-white/40 text-lg md:text-xl leading-relaxed font-light max-w-2xl border-l-2 border-[#D4AF37] pl-8">
              Exclusive archive editions and prototype releases. These pieces represent the pinnacle of Carry Culture—available only to verified District operatives.
            </p>
          </motion.div>
