        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-x-12 gap-y-24">
          <AnimatePresence mode="popLayout">
            {VAULT_DROPS.map((drop, i) => {
              const isActive = drop.status === 'active';
              const isSoldOut = drop.status === 'sold-out';
              const isUpcoming = drop.status === 'upcoming';

              // Define items that should appear in color
              const isColored = ['v1', 'v2', 'v3', 'v4', 'v5'].includes(drop.id);
              // Define items that show "View Archive" on hover
              const isViewableArchive = ['v1', 'v4', 'v5'].includes(drop.id);

              return (
                <motion.div
                  layout
                  key={drop.id}
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ delay: i * 0.1, duration: 0.6 }}
                  className="group relative"
                >
                  <div className="relative aspect-[3/4] bg-[#0d0d0d] overflow-hidden mb-8 border border-white/5 transition-all duration-700 hover:border-[#D4AF37]/30">
                    <img 
                      src={drop.image} 
                      alt={drop.name} 
                      className={`w-full h-full object-cover transition-transform duration-[6s] group-hover:scale-110 
                        ${isColored ? 'grayscale-0 opacity-100' : 'grayscale opacity-20 group-hover:grayscale-0 group-hover:opacity-100'}`}
                    />

                    {/* Status Overlays */}
                    {isSoldOut ? (
                      <>
                        <div className="absolute top-4 right-4 z-20">
                          <span className="text-[7px] tracking-[0.3em] font-black text-white/60 uppercase border border-white/10 px-3 py-1 bg-black/40 backdrop-blur-sm">Archived Piece</span>
                        </div>

                        {isViewableArchive ? (
                          <div className="absolute inset-0 bg-black/20 opacity-0 group-hover:opacity-100 transition-opacity flex flex-col items-center justify-center gap-6 backdrop-blur-sm">
                            <Link to={`/product/${drop.id}`}>
                              <button className="text-[9px] tracking-[0.5em] font-black uppercase text-white hover:text-[#D4AF37] transition-colors flex items-center gap-2">
                                <Eye size={12} /> View Archive
                              </button>
                            </Link>
                          </div>
                        ) : (
                          <div className="absolute inset-0 flex items-center justify-center bg-black/40">
                             {/* Dark overlay for other archived items without detail pages */}
                          </div>
                        )}
                      </>
                    ) : isUpcoming ? (
                      <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/60 backdrop-blur-sm opacity-0 group-hover:opacity-100 transition-all duration-500">
