import { createClient } from 'https://esm.sh/@supabase/supabase-js@2.39.7';

// We use placeholders to prevent the "supabaseUrl is required" crash.
// In a real environment, these should be set as process.env.SUPABASE_URL and process.env.SUPABASE_ANON_KEY
const supabaseUrl = process.env.SUPABASE_URL || 'https://placeholder-url.supabase.co';
const supabaseAnonKey = process.env.SUPABASE_ANON_KEY || 'placeholder-key';

// Only initialize if we have actual values, otherwise we'll handle the null client in components
export const isSupabaseConfigured = Boolean(process.env.SUPABASE_URL && process.env.SUPABASE_ANON_KEY);

export const supabase = createClient(supabaseUrl, supabaseAnonKey);

