  useEffect(() => {
    const fetchProducts = async () => {
      setLoading(true);
      try {
        if (!isSupabaseConfigured) {
          console.warn('Supabase not configured. Falling back to local data.');
          setProducts(PRODUCTS.filter(p => p.tag !== 'VAULT'));
