// Audio Helpers
function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

const Concierge: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isActive, setIsActive] = useState(false);
  const [isConnecting, setIsConnecting] = useState(false);
  const [isSpeaking, setIsSpeaking] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const sessionRef = useRef<any>(null);

  const startConcierge = async () => {
    setIsConnecting(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      inputAudioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });

      const session = await ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-12-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } },
          },
          systemInstruction: `You are the DSTRKT Concierge. You are a highly sophisticated, world-class personal shopper for the luxury streetwear brand DSTRKT. 
          Your tone is exclusive, professional, and deeply rooted in urban culture. You know that DSTRKT creates high-end duffel bags like the Nomad Catalyst, Urban Voyager, and Executive Slate.
          Your goal is to assist customers with product details, styling advice, and brand philosophy. Keep your responses concise and elegant.`,
        },
        callbacks: {
          onopen: () => {
            setIsActive(true);
            setIsConnecting(false);

            const source = inputAudioContextRef.current!.createMediaStreamSource(stream);
            const scriptProcessor = inputAudioContextRef.current!.createScriptProcessor(4096, 1, 1);

            scriptProcessor.onaudioprocess = (e) => {
              const inputData = e.inputBuffer.getChannelData(0);
              const int16 = new Int16Array(inputData.length);
              for (let i = 0; i < inputData.length; i++) {
                int16[i] = inputData[i] * 32768;
              }
              const pcmBlob = {
                data: encode(new Uint8Array(int16.buffer)),
                mimeType: 'audio/pcm;rate=16000',
              };
              session.sendRealtimeInput({ media: pcmBlob });
            };

            source.connect(scriptProcessor);
            scriptProcessor.connect(inputAudioContextRef.current!.destination);
          },
          onmessage: async (message) => {
            const audioData = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
            if (audioData) {
              setIsSpeaking(true);
              const ctx = audioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.current.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => s.stop());
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsSpeaking(false);
            }
          },
          onclose: () => stopConcierge(),
          onerror: (e) => console.error('Concierge Error:', e),
        },
      });

      sessionRef.current = session;
    } catch (err) {
      console.error('Failed to connect to Concierge:', err);
      setIsConnecting(false);
    }
  };

  const stopConcierge = () => {
    if (sessionRef.current) {
      // In a real implementation, we'd close the session properly
    }
    setIsActive(false);
    setIsConnecting(false);
    setIsSpeaking(false);
    sourcesRef.current.forEach(s => s.stop());
    sourcesRef.current.clear();
  };

  return (
    <>
      <div className="fixed bottom-8 right-8 z-[100]">
        <motion.button
          whileHover={{ scale: 1.1 }}
          whileTap={{ scale: 0.9 }}
          onClick={() => setIsOpen(true)}
          className="w-16 h-16 bg-white text-black rounded-full flex items-center justify-center shadow-2xl gold-glow transition-all duration-500 relative group"
        >
          <div className="absolute inset-0 bg-[#D4AF37] rounded-full animate-ping opacity-20 group-hover:opacity-40"></div>
          <Headphones size={24} className="relative z-10" />
        </motion.button>
      </div>

      <AnimatePresence>
        {isOpen && (
          <motion.div 
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-[110] flex items-center justify-center p-6 bg-black/95 backdrop-blur-xl"
          >
            <div className="max-w-xl w-full text-center space-y-12">
              <button 
                onClick={() => { setIsOpen(false); stopConcierge(); }}
                className="absolute top-12 right-12 text-white/40 hover:text-white transition-colors"
              >
                <X size={32} />
              </button>

              <div className="space-y-4">
                <p className="text-[#D4AF37] text-[10px] tracking-[0.8em] font-black uppercase">District Concierge</p>
                <h2 className="text-5xl font-black uppercase tracking-tighter italic">Personal Service.</h2>
              </div>

              <div className="flex flex-col items-center gap-12">
                <div className="relative">
                  <motion.div 
                    animate={isActive ? { scale: [1, 1.2, 1], opacity: [0.1, 0.3, 0.1] } : {}}
                    transition={{ repeat: Infinity, duration: 2 }}
                    className="absolute inset-0 bg-[#D4AF37] rounded-full blur-3xl"
                  />
                  <div className={`w-40 h-40 rounded-full border border-white/10 flex items-center justify-center relative z-10 transition-all duration-700 ${isActive ? 'bg-[#D4AF37] text-black border-[#D4AF37]' : 'bg-white/5 text-white'}`}>
                    {isConnecting ? (
                      <Loader2 className="animate-spin" size={48} />
                    ) : isActive ? (
                      isSpeaking ? <Volume2 size={48} className="animate-pulse" /> : <Mic size={48} />
                    ) : (
                      <MicOff size={48} className="opacity-20" />
                    )}
                  </div>
                </div>

                <div className="space-y-8 w-full">
                  <p className="text-white/40 text-sm tracking-widest uppercase font-bold max-w-sm mx-auto">
                    {isActive 
                      ? "The Concierge is listening. Ask about the collection or brand heritage."
                      : "Voice encryption ready. Tap below to initiate secure concierge session."}
                  </p>

                  <button 
                    onClick={isActive ? stopConcierge : startConcierge}
                    disabled={isConnecting}
                    className={`w-full py-6 text-[11px] tracking-[0.5em] font-black uppercase transition-all duration-500
                      ${isActive ? 'bg-red-500/10 border border-red-500/20 text-red-500 hover:bg-red-500 hover:text-white' : 'bg-white text-black hover:bg-[#D4AF37]'}`}
                  >
                    {isActive ? 'Terminate Session' : 'Initiate Concierge'}
                  </button>
                </div>
              </div>

              <div className="flex justify-center gap-8 text-[9px] tracking-[0.4em] font-black text-white/20 uppercase">
                <span className="flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-green-500"></div> AES-256 SECURE</span>
                <span className="flex items-center gap-2"><div className="w-1.5 h-1.5 rounded-full bg-[#D4AF37]"></div> PRIORITY ACCESS</span>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

