  const isSoldOut = drop.status === 'sold-out';
  const isActive = drop.status === 'active';

  const ButtonContent = () => (
    <button className={`w-full py-5 text-[10px] tracking-[0.4em] font-black uppercase transition-all duration-500 border border-white/10 hover:border-[#D4AF37] ${isUpcoming ? 'bg-transparent text-white' : 'bg-[#D4AF37] text-black'} ${(!hasAccess && !isSoldOut) ? 'opacity-50' : ''}`}>
      {isUpcoming ? 'Join Waiting List' : isSoldOut ? 'Archived' : hasAccess ? 'Enter Private Shop' : 'Access Restricted'}
    </button>
  );

  return (
    <motion.div 
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      transition={{ delay: index * 0.1, duration: 0.8 }}
      viewport={{ once: true }}
      className="group"
    >
      <div className="relative aspect-[4/5] bg-[#0d0d0d] overflow-hidden mb-8 border border-white/5 gold-glow transition-all duration-500">
        <img 
          src={drop.image} 
          alt={drop.name} 
          className={`w-full h-full object-cover transition-transform duration-[4s] group-hover:scale-110 ${isSoldOut ? 'grayscale opacity-30' : 'grayscale group-hover:grayscale-0'}`}
        />
        <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-80"></div>

        {isSoldOut && (
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-[10px] tracking-[0.8em] font-black text-white/40 uppercase rotate-[-45deg] border-2 border-white/10 px-8 py-2">Sold Out</span>
          </div>
        )}

        {!hasAccess && !isUpcoming && !isSoldOut && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/60 backdrop-blur-sm z-10">
            <div className="text-center p-6">
              <ShieldAlert className="text-[#D4AF37] mx-auto mb-4" size={32} />
              <p className="text-[10px] tracking-[0.4em] font-black text-white uppercase">Access Restricted</p>
            </div>
          </div>
        )}

        <div className="absolute top-8 right-8">
          {isUpcoming ? (
            <div className="flex items-center gap-2 bg-[#D4AF37] text-black px-4 py-2 rounded-full text-[9px] font-black tracking-widest">
              <Clock size={12} /> DROPS SOON
            </div>
          ) : !isSoldOut && (
            <div className="flex items-center gap-2 bg-white text-black px-4 py-2 rounded-full text-[9px] font-black tracking-widest">
              <Lock size={12} /> {hasAccess ? 'ACTIVE' : 'LOCKED'}
            </div>
          )}
        </div>

        <div className="absolute bottom-8 left-8 right-8">
          <p className="text-[10px] tracking-[0.4em] font-bold text-[#D4AF37] mb-2 uppercase">{drop.status.replace('-', ' ')}</p>
          <h4 className="text-2xl font-black uppercase tracking-tighter mb-4">{drop.name}</h4>
          <p className="text-[11px] text-white/60 leading-relaxed font-light line-clamp-2">{drop.description}</p>
        </div>
      </div>

      {isActive && hasAccess ? (
        <Link to="/vault/shop" className="block w-full">
          <ButtonContent />
        </Link>
      ) : (
        <div className="block w-full cursor-not-allowed">
          <ButtonContent />
        </div>
      )}
    </motion.div>
  );
};

const Vault: React.FC = () => {
  const [drops, setDrops] = useState<VaultDrop[]>([]);
  const [hasVaultAccess, setHasVaultAccess] = useState(false);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchVaultData = async () => {
      setLoading(true);
      try {
        // Fetch Vault Drops
        const { data: vaultData, error: vaultError } = await supabase
          .from('vault_drops')
          .select('*')
          .order('release_date', { ascending: false });

        if (!vaultError && vaultData) {
          setDrops(vaultData.map(d => ({
            id: d.id,
            name: d.name,
            releaseDate: d.release_date,
            image: d.image_url,
            status: d.status,
            description: d.description
          })));
        } else {
          setDrops(VAULT_DROPS);
        }

        // Fetch Profile for Vault Access (Mocking current user check)
        const { data: profileData } = await supabase
          .from('profiles')
          .select('vault_access')
          .limit(1)
          .single();

        if (profileData) {
          setHasVaultAccess(profileData.vault_access);
        }
      } catch (err) {
        console.error('Vault fetch error:', err);
        setDrops(VAULT_DROPS);
      } finally {
        setLoading(false);
      }
    };

    fetchVaultData();
  }, []);

  return (
    <main className="bg-black min-h-screen pt-40 pb-40 selection:bg-[#D4AF37] selection:text-black">
      <section className="max-w-[1800px] mx-auto px-6 md:px-12">
        <header className="mb-32 max-w-4xl">
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
            <p className="text-[#D4AF37] text-xs tracking-[0.8em] font-bold mb-8 uppercase flex items-center gap-4">
              <span className="w-12 h-[1px] bg-[#D4AF37]"></span> Members Exclusive
            </p>
            <h1 className="text-6xl md:text-9xl font-black tracking-[-0.05em] uppercase mb-12 leading-none">
              The<br />Vault.
            </h1>
            <p className="text-white/40 text-lg md:text-xl leading-relaxed font-light max-w-2xl italic">
              The Vault is where rare drops live. Limited releases, curated pieces, and members-only access — unlocked when the countdown hits zero.
            </p>
          </motion.div>
        </header>

        {loading ? (
          <div className="flex items-center justify-center py-40">
            <Loader2 className="animate-spin text-[#D4AF37]" size={40} />
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
            {drops.map((drop, idx) => (
              <VaultItem key={drop.id} drop={drop} index={idx} hasAccess={hasVaultAccess} />
            ))}
          </div>
        )}

        <motion.div 
          initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} viewport={{ once: true }}
          className="mt-40 p-12 md:p-24 border border-white/5 bg-[#050505] flex flex-col md:flex-row gap-12 items-center justify-between"
        >
          <div className="max-w-xl">
            <h3 className="text-3xl font-black uppercase mb-6 tracking-tighter">Become a District Member.</h3>
            <p className="text-white/40 text-sm leading-relaxed mb-8">
              Gain first access to capsule collections, collaborative drops, and secret events. Members are notified 24 hours before any public release.
            </p>
            <div className="flex gap-4 text-[10px] tracking-widest text-white/40 uppercase">
              <Info size={16} className="text-[#D4AF37] shrink-0" />
              <p>Registration required for active drops.</p>
