                className="absolute top-12 right-12 text-white/40 hover:text-white transition-colors p-4"
              >
                <X size={32} />
              </button>

              <div className="space-y-4">
                <p className="text-[#D4AF37] text-[10px] tracking-[0.8em] font-black uppercase">District Concierge</p>
                <h2 className="text-5xl font-black uppercase tracking-tighter italic leading-none">Personal Service.</h2>
              </div>

              <div className="flex flex-col items-center gap-12">
                <div className="relative">
                  <motion.div 
                    animate={isActive ? { scale: [1, 1.2, 1], opacity: [0.1, 0.3, 0.1] } : {}}
