                    ${errorState ? 'border-red-500 text-red-500 bg-red-500/10' : 
                      isActive ? 'bg-[#D4AF37] text-black border-[#D4AF37]' : 'bg-white/5 text-white border-white/10'}`}>
                    {isConnecting ? (
                      <Loader2 className="animate-spin" size={48} />
