          },
          onmessage: async (message) => {
            // Check for turn completion or text to manage processing state
            if (message.serverContent?.modelTurn) {
              setIsProcessing(false);
            }

            const audioData = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (audioData) {
              setIsSpeaking(true);
              const ctx = audioContextRef.current!;
              nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);

              const buffer = await decodeAudioData(decode(audioData), ctx, 24000, 1);
              const source = ctx.createBufferSource();
              source.buffer = buffer;
              source.connect(ctx.destination);
              source.addEventListener('ended', () => {
                sourcesRef.current.delete(source);
                if (sourcesRef.current.size === 0) setIsSpeaking(false);
              });
              source.start(nextStartTimeRef.current);
              nextStartTimeRef.current += buffer.duration;
              sourcesRef.add(source);
            }

            if (message.serverContent?.interrupted) {
              sourcesRef.current.forEach(s => {
                try { s.stop(); } catch(e) {}
              });
              sourcesRef.current.clear();
              nextStartTimeRef.current = 0;
              setIsSpeaking(false);
              setIsProcessing(false);
            }
          },
          onclose: () => stopConcierge(),
          onerror: (e) => {
            console.error('Concierge Error:', e);
            setErrorState("Communication protocol error.");
            stopConcierge();
          },
        },
      });

      sessionPromiseRef.current = sessionPromise;
    } catch (err: any) {
      setErrorState(err.message || "Unable to establish connection.");
      setIsConnecting(false);
      stopConcierge();
    }
  };

  const stopConcierge = () => {
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }

    setIsActive(false);
    setIsConnecting(false);
    setIsSpeaking(false);
    setIsProcessing(false);
