          <ButtonContent />
        </div>
      )}
    </motion.div>
  );
};

const Vault: React.FC = () => {
  const [drops, setDrops] = useState<VaultDrop[]>([]);
  const [hasVaultAccess, setHasVaultAccess] = useState(false);
  const [loading, setLoading] = useState(true);
  const [user, setUser] = useState<any>(null);

  useEffect(() => {
    // 1. Initial Auth Check
    supabase.auth.getSession().then(({ data: { session } }) => {
      setUser(session?.user ?? null);
      if (session?.user) {
        setHasVaultAccess(true); // Grant access if logged in
        fetchUserSpecificProfile(session.user.id);
      }
    });

    // 2. Listen for Auth Changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setUser(session?.user ?? null);
      if (session?.user) {
        setHasVaultAccess(true);
        fetchUserSpecificProfile(session.user.id);
      } else {
        setHasVaultAccess(false);
      }
    });

    fetchVaultDrops();

    return () => subscription.unsubscribe();
  }, []);

  const fetchUserSpecificProfile = async (userId: string) => {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('vault_access')
        .eq('id', userId)
        .single();

      // If profile exists and has explicit vault_access, use it. 
      // Otherwise, keep the default 'true' for logged-in members.
      if (!error && data) {
        setHasVaultAccess(data.vault_access ?? true);
      }
    } catch (err) {
      console.error('Profile fetch failed, defaulting access to true for member.');
    }
  };

  const fetchVaultDrops = async () => {
    try {
      const { data, error } = await supabase
        .from('vault_drops')
        .select('*')
        .order('release_date', { ascending: false });

      if (!error && data && data.length > 0) {
        setDrops(data.map(d => ({
          id: d.id,
          name: d.name,
          releaseDate: d.release_date,
          image: d.image_url,
          status: d.status || 'active',
          description: d.description
        })));
      } else {
        setDrops(VAULT_DROPS);
      }
    } catch (err) {
      setDrops(VAULT_DROPS);
    } finally {
      setLoading(false);
    }
  };

  return (
    <main className="bg-black min-h-screen pt-40 pb-40 selection:bg-[#D4AF37] selection:text-black">
      <section className="max-w-[1800px] mx-auto px-6 md:px-12">
        <header className="mb-32 max-w-4xl">
          <motion.div initial={{ opacity: 0, x: -20 }} animate={{ opacity: 1, x: 0 }}>
            <p className="text-[#D4AF37] text-xs tracking-[0.8em] font-bold mb-8 uppercase flex items-center gap-4">
              <span className="w-12 h-[1px] bg-[#D4AF37]"></span> 
              {user ? 'Priority Access Enabled' : 'Members Exclusive'}
            </p>
            <h1 className="text-6xl md:text-9xl font-black tracking-[-0.05em] uppercase mb-12 leading-none">
              The<br />Vault.
            </h1>
            <p className="text-white/40 text-lg md:text-xl leading-relaxed font-light max-w-2xl italic">
              {user 
                ? `Welcome back, Operative ${user.email?.split('@')[0].toUpperCase()}. Your clearance level has been verified. The archive is now unlocked.` 
                : "The Vault is where rare drops live. Limited releases, curated pieces, and members-only access — unlocked for verified operatives."}
            </p>
          </motion.div>
        </header>

        {loading ? (
          <div className="flex items-center justify-center py-40">
            <Loader2 className="animate-spin text-[#D4AF37]" size={40} />
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12">
            {drops.map((drop, idx) => (
              <VaultItem key={drop.id} drop={drop} index={idx} hasAccess={hasVaultAccess} />
            ))}
          </div>
        )}

        {!user && (
          <motion.div 
            initial={{ opacity: 0 }} whileInView={{ opacity: 1 }} viewport={{ once: true }}
            className="mt-40 p-12 md:p-24 border border-white/5 bg-[#050505] flex flex-col md:flex-row gap-12 items-center justify-between"
          >
            <div className="max-w-xl">
              <h3 className="text-3xl font-black uppercase mb-6 tracking-tighter">Become a District Member.</h3>
              <p className="text-white/40 text-sm leading-relaxed mb-8">
                Gain first access to capsule collections, collaborative drops, and secret events. Members are notified 24 hours before any public release.
              </p>
              <div className="flex gap-4 text-[10px] tracking-widest text-white/40 uppercase">
                <Info size={16} className="text-[#D4AF37] shrink-0" />
                <p>Registration required for active drops.</p>
              </div>
            </div>
            <Link to="/account/profile">
              <button className="bg-white text-black px-12 py-6 text-[12px] tracking-[0.4em] font-black uppercase hover:bg-[#D4AF37] transition-colors">
                Register for access
              </button>
            </Link>
          </motion.div>
        )}
      </section>
    </main>
  );
};

