import { supabase } from './supabase';

const Profile: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [loading, setLoading] = useState(true);
  const [authMode, setAuthMode] = useState<'login' | 'register'>('login');
  const [isEditing, setIsEditing] = useState(false);

  // Auth Form State
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [displayName, setDisplayName] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);
  const [authLoading, setAuthLoading] = useState(false);

  // Profile Data State
  const [profile, setProfile] = useState<any>({
    displayName: 'GUEST_OPERATIVE',
    email: '',
    memberSince: 'N/A',
    vault_access: false
  });

  useEffect(() => {
    // Check initial session
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session) fetchProfile(session);
      setLoading(false);
    });

    // Listen for auth changes
    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      setSession(session);
      if (session) fetchProfile(session);
    });

    return () => subscription.unsubscribe();
  }, []);

  const fetchProfile = async (currentSession: any) => {
    if (!currentSession?.user) return;

    try {
      // Try to get extended profile info from DB
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', currentSession.user.id)
        .single();

      // Get date from DB created_at or Auth user created_at
      const creationDate = data?.created_at || currentSession.user.created_at;
      const d = new Date(creationDate);
      const mm = String(d.getMonth() + 1).padStart(2, '0');
      const yy = String(d.getFullYear()).slice(-2);

      setProfile({
        // Priority: Database full_name, then metadata from registration, then email handle
        displayName: data?.full_name || currentSession.user.user_metadata?.full_name || currentSession.user.email?.split('@')[0].toUpperCase() || 'ANONYMOUS_MEMBER',
        email: currentSession.user.email,
        memberSince: `${mm}/${yy}`,
        vault_access: data?.vault_access || false
      });
    } catch (err) {
      console.error('Error fetching profile:', err);
      // Fallback for immediate UI update after registration
      const d = new Date(currentSession.user.created_at);
      const mm = String(d.getMonth() + 1).padStart(2, '0');
      const yy = String(d.getFullYear()).slice(-2);

      setProfile({
        displayName: currentSession.user.user_metadata?.full_name || currentSession.user.email?.split('@')[0].toUpperCase(),
        email: currentSession.user.email,
