            <div className="absolute top-0 left-0 w-full h-1 bg-white/5 overflow-hidden">
              <motion.div 
                animate={{ x: ['-100%', '100%'] }}
                transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
                className="w-1/2 h-full bg-[#D4AF37]"
              />
            </div>
            <Clock size={32} className="text-[#D4AF37] mb-8 animate-pulse" />
            <div className="flex gap-6 md:gap-12 mb-8">
              {[
                { val: timeLeft.days, label: 'DAYS' },
                { val: timeLeft.hours, label: 'HRS' },
                { val: timeLeft.minutes, label: 'MIN' },
                { val: timeLeft.seconds, label: 'SEC' }
              ].map((t, i) => (
                <div key={i} className="space-y-2">
                  <p className="text-4xl md:text-6xl font-black tracking-tighter font-bebas">{t.val.toString().padStart(2, '0')}</p>
                  <p className="text-[9px] tracking-[0.3em] font-bold text-white/30">{t.label}</p>
                </div>
              ))}
            </div>
            <p className="text-[10px] tracking-[0.5em] font-black uppercase text-[#D4AF37]">Drop Sequence Initiated</p>
          </div>
        </div>
      </section>

      {/* Technical Materials Section - Restored */}
      <section className="py-40 px-6 md:px-12 max-w-[1800px] mx-auto">
        <header className="mb-24 max-w-4xl">
          <motion.div initial={{ opacity: 0, x: -20 }} whileInView={{ opacity: 1, x: 0 }} viewport={{ once: true }}>
            <p className="text-[10px] tracking-[0.6em] font-black uppercase text-[#D4AF37] mb-4">Technical Specifications</p>
            <h2 className="text-4xl md:text-8xl font-black uppercase tracking-tighter leading-none italic text-white mb-10">Materials.</h2>
            <p className="text-white/40 text-lg md:text-xl leading-relaxed font-light italic border-l-2 border-[#D4AF37] pl-8">
              Architectural integrity meets textile innovation. We source high-performance composites and military-grade fabrics to ensure your gear survives the shift from street to summit.
            </p>
          </motion.div>
        </header>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
          {features.map((f, i) => (
            <motion.div 
              key={i}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: i * 0.1 }}
              className="p-10 border border-white/5 bg-white/[0.01] hover:bg-white/[0.03] transition-all group"
            >
              <f.icon size={32} className="text-[#D4AF37] mb-8 group-hover:scale-110 transition-transform" strokeWidth={1.5} />
              <h4 className="text-[11px] tracking-[0.4em] font-black uppercase text-white mb-4">{f.title}</h4>
              <p className="text-[10px] text-white/40 leading-relaxed uppercase tracking-[0.1em] font-bold">{f.desc}</p>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Culture Section */}
      <section className="py-32 px-6 md:px-12 max-w-[1800px] mx-auto overflow-hidden">
        <header className="mb-24">
          <p className="text-[10px] tracking-[0.6em] font-black uppercase text-[#D4AF37] mb-4">The District Archive</p>
          <h2 className="text-4xl md:text-8xl font-black uppercase tracking-tighter leading-none italic text-white">Culture.</h2>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 auto-rows-[300px] md:auto-rows-[400px]">
          {(cultureItems.length > 0 ? cultureItems : featuredProducts).map((item, i) => (
            <motion.div
              layout
              key={item.id || i}
              initial={{ opacity: 0, scale: 0.95 }}
              whileInView={{ opacity: 1, scale: 1 }}
              viewport={{ once: true }}
              className={`relative group overflow-hidden border border-white/10 ${i === 0 ? 'lg:col-span-2 lg:row-span-2' : ''}`}
            >
              <img src={item.image_url || item.image} alt={item.title || item.name} className="w-full h-full object-cover transition-transform duration-[3s] group-hover:scale-110" />
              <div className="absolute inset-0 bg-black/60 opacity-0 group-hover:opacity-100 transition-opacity duration-500 flex flex-col justify-end p-8 md:p-12">
                <p className="text-[10px] tracking-[0.4em] font-black text-[#D4AF37] uppercase mb-2">{item.tag || item.collection || 'DISTRICT'}</p>
                <h3 className="text-2xl md:text-4xl font-black uppercase tracking-tighter mb-8 leading-none italic text-white">{item.title || item.name}</h3>
                <button onClick={() => setSelectedPiece(item)} className="text-[10px] tracking-[0.6em] font-black uppercase text-white border-b border-white pb-2 w-fit hover:text-[#D4AF37] transition-all">
                  View Piece
                </button>
              </div>
            </motion.div>
          ))}
        </div>
      </section>

      {/* Lightbox Modal */}
      <AnimatePresence>
        {selectedPiece && (
          <motion.div 
            initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
            className="fixed inset-0 z-[100] flex items-center justify-center p-6 md:p-24"
          >
            <div className="absolute inset-0 bg-black/95 backdrop-blur-2xl" onClick={() => setSelectedPiece(null)} />
            <motion.div 
              initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} exit={{ scale: 0.9, opacity: 0 }}
              className="relative w-full max-w-7xl h-full flex flex-col lg:flex-row bg-[#0d0d0d] border border-white/10 overflow-hidden"
            >
              <button onClick={() => setSelectedPiece(null)} className="absolute top-8 right-8 z-[110] text-white/40 hover:text-white"><X size={32} /></button>
              <div className="lg:w-3/5 bg-black overflow-hidden h-1/2 lg:h-full">
                <img src={selectedPiece.image_url || selectedPiece.image} alt={selectedPiece.title || selectedPiece.name} className="w-full h-full object-cover" />
              </div>
              <div className="lg:w-2/5 p-8 md:p-16 flex flex-col justify-center">
                <p className="text-[#D4AF37] text-[10px] tracking-[0.8em] font-black uppercase mb-8">{selectedPiece.tag || 'DSTRKT'}</p>
                <h2 className="text-4xl md:text-6xl font-black uppercase tracking-tighter italic text-white mb-10 leading-[0.85]">{selectedPiece.title || selectedPiece.name}</h2>
                <p className="text-white/60 text-base md:text-lg leading-relaxed font-light italic mb-12 border-l-2 border-[#D4AF37] pl-8">"{selectedPiece.description}"</p>
                {selectedPiece.product_id && (
                  <Link to={`/product/${selectedPiece.product_id}`} onClick={() => setSelectedPiece(null)}>
                    <button className="w-full bg-white text-black py-6 text-[11px] tracking-[0.5em] font-black uppercase hover:bg-[#D4AF37] transition-all flex items-center justify-center gap-4">
                      Explore Product <ExternalLink size={16} />
                    </button>
                  </Link>
                )}
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </main>
  );
};

export default Home;
